```python
import re

class SuperValidator:
    """
    Classe utilitaire pour valider des chaînes ou structures issues de l'utilisateur
    afin d'éviter les injections ou comportements indésirables.
    """

    @staticmethod
    def validate(page):
        """
        Valide une URL ou un paramètre de chemin d’accès.

        Autorise uniquement les lettres, chiffres, tirets, underscores et slashs.
        """
        if not page:
            return True  # aucun problème

        if not re.match(r'^[\w\-/]*$', page):
            raise ValueError("URL invalide ou tentative d'injection détectée")
        return True

    @staticmethod
    def is_alphanumeric(value):
        """
        Vérifie que la chaîne est alphanumérique uniquement.
        """
        return bool(re.match(r'^[a-zA-Z0-9]+$', value))

    @staticmethod
    def is_safe_query(value):
        """
        Vérifie que la chaîne ne contient pas de caractères suspects pour une requête SQL.
        """
        pattern = re.compile(r"(?:')|(?:--)|(/\*(?:.|[\n\r])*?\*/)|(\b(select|update|delete|insert|drop|alter|exec|union|create)\b)", re.IGNORECASE)
        return not pattern.search(value)

    @staticmethod
    def sanitize_text(value):
        """
        Nettoie une chaîne de texte pour en retirer les caractères à risque.
        """
        return re.sub(r"[^\w\s\-\_]", "", value)

    @staticmethod
    def is_valid_slug(value):
        """
        Vérifie qu'un slug est correctement formaté.
        """
        return bool(re.match(r'^[a-z0-9]+(?:-[a-z0-9]+)*$', value))
```

