## ✅ Proposition de structure finale – 100 % dynamique

### `index.html` :

```html
<!DOCTYPE html>
<html lang="{{ lang or 'fr' }}">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">

  {% if title %}
    <title>{{ title }}</title>
  {% endif %}

  {% for meta in metas %}
    <meta 
      {% for key, value in meta.items() %}
        {{ key }}="{{ value }}"
      {% endfor %}
    >
  {% endfor %}

  {% for css in css_links %}
    <link rel="stylesheet" href="{{ css }}">
  {% endfor %}
</head>
<body>

  {% if header %}
    <header id="site-header">
      {% for block in header %}
        {{ block }}
      {% endfor %}
    </header>
  {% endif %}

  {% if nav and not nav_in_header %}
    <nav id="site-navigation">
      {% for item in nav %}
        {{ item }}
      {% endfor %}
    </nav>
  {% endif %}

  {% if sidebar %}
    <aside id="site-sidebar">
      {% for item in sidebar %}
        {{ item }}
      {% endfor %}
    </aside>
  {% endif %}

  <main id="site-content">
    {% for block in sections %}
      <section class="content-block">
        {% for element in block %}
          {{ element }}
        {% endfor %}
      </section>
    {% endfor %}
  </main>

  {% if footer %}
    <footer id="site-footer">
      {% for item in footer %}
        {{ item }}
      {% endfor %}
    </footer>
  {% endif %}

  {% for js in js_scripts %}
    <script src="{{ js }}"></script>
  {% endfor %}
</body>
</html>
```

