import sqlite3

def get_or_create_object(conn, label):
    cur = conn.cursor()
    # Vérifie si l'objet avec ce label existe
    cur.execute("""
        SELECT id FROM Labels WHERE label = ?
    """, (label,))
    result = cur.fetchone()
    if result:
        return result[0]

    # Crée un nouvel objet
    cur.execute("INSERT INTO Objects DEFAULT VALUES")
    obj_id = cur.lastrowid
    cur.execute("INSERT INTO Labels (id, label) VALUES (?, ?)", (obj_id, label))
    conn.commit()
    return obj_id

def get_or_create_relation_object(conn, relation_name):
    # Vérifie si la relation existe comme objet avec ce label
    return get_or_create_object(conn, relation_name)

def create_relation(conn, src_id, relation_type, target_id):
    relation_id = get_or_create_relation_object(conn, relation_type)
    cur = conn.cursor()
    cur.execute("""
        INSERT INTO Relations (src_id, relation_id, target_id) VALUES (?, ?, ?)
    """, (src_id, relation_id, target_id))
    conn.commit()

def create_meta(conn, parent_id, name, value):
    # Crée un meta-objet
    cur = conn.cursor()
    cur.execute("INSERT INTO Objects DEFAULT VALUES")
    meta_id = cur.lastrowid

    # Lier à l’objet principal
    create_relation(conn, parent_id, "meta_of", meta_id)

    # Enregistrer le nom
    name_id = get_or_create_object(conn, name)
    create_relation(conn, name_id, "label_of", name_id)
    create_relation(conn, meta_id, "meta_name_of", name_id)

    # Enregistrer la valeur
    value_id = get_or_create_object(conn, str(value))
    create_relation(conn, value_id, "label_of", value_id)
    create_relation(conn, meta_id, "meta_value_of", value_id)

def register_object_recursive(db_path, objects_list):
    conn = sqlite3.connect(db_path)
    try:
        for obj_data in objects_list:
            print(f"🔹 Enregistrement de : {obj_data}")
            obj_id = get_or_create_object(conn, obj_data["nom"])

            # Ajout du type (comme meta)
            if "type" in obj_data:
                type_id = get_or_create_object(conn, obj_data["type"])
                create_relation(conn, obj_id, "type_of", type_id)
                create_meta(conn, obj_id, "type", obj_data["type"])

            # Ajout du nom (comme meta aussi)
            create_meta(conn, obj_id, "nom", obj_data["nom"])

            # Ajout des relations si présentes
            if "relations" in obj_data:
                for rel in obj_data["relations"]:
                    if "type" in rel and "target" in rel:
                        rel_type = rel["type"]
                        target_id = get_or_create_object(conn, rel["target"])
                        create_relation(conn, obj_id, rel_type, target_id)
    finally:
        conn.close()
```

